1	/**
2	 * 小满CRM — 索引快照抓取器
3	 *
4	 * 只抓会话列表页的关键字段，不点进单个客户。
5	 * 300个客户约60秒完成。
6	 *
7	 * 用法: node snapshot.mjs
8	 * 前置条件: Chrome 端口9222已开启，小满已登录并在TM消息页
9	 */
10	
11	import { chromium } from 'playwright';
12	import { writeFileSync, mkdirSync, existsSync } from 'fs';
13	import { join, dirname } from 'path';
14	import { fileURLToPath } from 'url';
15	
16	const __dirname = dirname(fileURLToPath(import.meta.url));
17	const DATA_DIR = join(__dirname, '..', 'data');
18	const SNAPSHOT_DIR = join(DATA_DIR, 'snapshots');
19	const CDP_URL = 'http://127.0.0.1:9222';
20	
21	// 确保目录存在
22	if (!existsSync(SNAPSHOT_DIR)) mkdirSync(SNAPSHOT_DIR, { recursive: true });
23	
24	async function connect() {
25	  const browser = await chromium.connectOverCDP(CDP_URL);
26	  const ctx = browser.contexts()[0];
27	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
28	  if (!page) throw new Error('未找到小满页面');
29	  const talkFrame = page.frames()[1];
30	  if (!talkFrame) throw new Error('未找到聊天 iframe');
31	  return { browser, ctx, page, talkFrame };
32	}
33	
34	async function scrollConversationList(frame) {
35	  // 滚动到底部多次以确保所有300+联系人都加载到DOM中
36	  const container = await frame.evaluateHandle(() => {
37	    return document.querySelector('.seller-conversation-list') ||
38	      document.querySelector('.conversation-list-content') ||
39	      document.querySelector('.im-conversation-list-container');
40	  });
41	
42	  if (!container) { await container.dispose(); return; }
43	
44	  let lastScrollTop = -1;
45	  let sameCount = 0;
46	  for (let i = 0; i < 40; i++) { // 最多滚动40次
47	    const scrollTop = await container.evaluate(el => {
48	      el.scrollTop += 600;
49	      return el.scrollTop;
50	    });
51	    // 如果连续3次滚动位置不变，说明到底了
52	    if (scrollTop === lastScrollTop) {
53	      sameCount++;
54	      if (sameCount >= 3) break;
55	    } else {
56	      sameCount = 0;
57	      lastScrollTop = scrollTop;
58	    }
59	    await new Promise(r => setTimeout(r, 150));
60	  }
61	  await container.dispose();
62	}
63	
64	async function getIndexSnapshot(frame) {
65	  return frame.evaluate(() => {
66	    return Array.from(document.querySelectorAll('.contact-item-container')).map(el => {
67	      const text = el.textContent || '';
68	
69	      // 提取名称
70	      const nameEl = el.querySelector('.contact-right');
71	      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
72	      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
73	      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';
74	
75	      // 提取未读状态
76	      const isUnread = text.includes('[未读]');
77	
78	      // 提取时间戳
79	      const timeMatch = nameText.match(/(\d{2,4}[-:\/]\d{1,2}[-:\/]?\d{0,2})/);
80	      const lastTime = timeMatch ? timeMatch[1] : '';
81	
82	      // 提取最后一条消息内容
83	      const lastMsg = nameText
84	        .replace(/^.+?\d{2,4}[-:\/]\d{1,2}[-:\/]?\d{0,2}\s*/, '')
85	        .replace(/\[(未读|已读)\]\s*/, '')
86	        .trim()
87	        .substring(0, 200);
88	
89	      // 判断最后一条消息方向
90	      // 我方发出的消息在列表摘要中通常有特殊前缀或格式
91	      const isFromUs = lastMsg.includes('以上内容') || // 我方卡片消息
92	        lastMsg.includes('发送了') || // 我方发送了文件
93	        lastMsg.includes('[文件]') ||
94	        false;
95	
96	      return {
97	        name,
98	        isUnread,
99	        lastTime,
100	        lastMessageSnippet: lastMsg,
101	        lastMsgDirection: isFromUs ? 'sent' : 'received' // 粗略判断
102	      };
103	    });
104	  });
105	}
106	
107	async function main() {
108	  console.log('[snapshot] 连接小满...');
109	  const { talkFrame } = await connect();
110	
111	  const startTime = Date.now();
112	
113	  console.log('[snapshot] 滚动会话列表加载全部联系人...');
114	  await scrollConversationList(talkFrame);
115	
116	  console.log('[snapshot] 提取索引快照...');
117	  const customers = await getIndexSnapshot(talkFrame);
118	
119	  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
120	
121	  const now = new Date();
122	  const dateStr = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
123	  const filename = `snapshot_${dateStr}.json`;
124	
125	  const snapshot = {
126	    capturedAt: now.toISOString(),
127	    totalCustomers: customers.length,
128	    unreadCount: customers.filter(c => c.isUnread).length,
129	    elapsedSeconds: parseFloat(elapsed),
130	    customers
131	  };
132	
133	  writeFileSync(join(SNAPSHOT_DIR, filename), JSON.stringify(snapshot, null, 2));
134	  console.log(`[snapshot] 完成: ${customers.length}个客户, ${elapsed}s → ${filename}`);
135	}
136	
137	main().catch(err => {
138	  console.error('[snapshot] 错误:', err.message);
139	  process.exit(1);
140	});
