  'K_activate': {label:'⚪ 新线索/低互动 — 待激活', items:[]},
};

for (const c of data.customers) {
  const msg=(c.latestMessageContent||'').trim();
  const msgLow=msg.toLowerCase();
  const da=daysAgo(c.lastContactTime);
  const isUnread=c.isUnread||c.unreadCount>0;
  const isFromUs=c.latestMessageType==='send';
  const hasAuto=/automatic reception|no longer intervene/i.test(msg);

  // A: Unread messages
  if (isUnread) { groups.A_urgent_unread.items.push(c); continue; }

  // B: Auto-reply dropped (system said it won't reply anymore, but customer may need attention)
  if (hasAuto && c.priority<='P1') { groups.B_auto_fail.items.push(c); continue; }

  // I: After-sales
  if (/complaint|return|refund|damage|defect|wrong|quality issue|退换|退款|投诉|破损|纠纷|欺诈/.test(msgLow)) {
    groups.I_after_sales.items.push(c); continue;
  }

  // Priority-based classification with content signals
  const hasPrice=/price|quote|cost|how much|报价|价格|\$[0-9]|usd|dollar|كم|сколько|cuánto/i.test(msgLow);
  const hasShipping=/ship|delivery|envío|livraison|物流|dhl|fedex|freight|shipping cost|快递|海运/i.test(msgLow);
  const hasPayment=/payment|pay|deposit|付款|pago|paiement|دفع|transfer|pi\b|proforma/i.test(msgLow);
  const hasSample=/sample|muestra|échantillon|样品|试用|试单/i.test(msgLow);
  const hasGreeting=/hello|hi\b|how are you|bonjour|hola| salut\b|nice to meet/i.test(msgLow);
  const hasOrder=/order|place|confirm|下单|采购/i.test(msgLow);

  // Check if customer's message was from customer (msgFromCustomer)
  const custAsked=c.msgFromCustomer===true;

  // F: Payment discussion
  if (hasPayment && isFromUs && da<30) { groups.F_payment.items.push(c); continue; }

  // C: Customer asked about price - awaiting quote/followup
  if (custAsked && hasPrice && da<30) { groups.C_price_asked.items.push(c); continue; }

  // D: We sent quote, customer silent
  if (isFromUs && hasPrice && da>=3 && da<60) { groups.D_quote_sent.items.push(c); continue; }
  if (isFromUs && hasPrice && da>=60) { groups.K_activate.items.push(c); continue; } // old quotes → activate

  // E: Shipping/negotiation phase
  if (hasShipping && isFromUs && da<30) { groups.E_shipping_phase.items.push(c); continue; }
  if (isFromUs && (hasPayment||hasShipping) && da<60) { groups.E_shipping_phase.items.push(c); continue; }

  // G: In transit
  if (isFromUs && hasShipping && da>=7 && da<60 && msgLow.includes('ship')) { groups.G_in_transit.items.push(c); continue; }

  // H: Delivered
  if (/received|arrived|收到|已签收|feedback|review|复购/i.test(msgLow) && da<90) {
    groups.H_delivered.items.push(c); continue;
  }

  // J: Keep warm (P0-P2 with some recent interaction)
  if (c.priority<='P2' && da<14) { groups.J_warm.items.push(c); continue; }

  // K: Activate (P3 + older P2)
  groups.K_activate.items.push(c);
}

