    console.log(' '+dir+' '+c.name.padEnd(22)+'| '+c.countryCode.padEnd(3)+'| L'+lvl+' | '+daStr.padEnd(5)+'| '+msg);
  }
  if (g.items.length>20) console.log('    ... 还有'+(g.items.length-20)+'人');
  console.log('');
}
