    return { cat: 'K', label: '旧报价·已沉寂', emoji: '⚪', desc: '报过价但很久没互动' };
  }

  // === 样品阶段 ===
  if (sample && realCustMsg) {
    return { cat: 'S', label: '客户要样品·待处理', emoji: '📦', desc: '客户问了样品事宜' };
  }

  // === 付款相关 ===
  if (payment && realOurMsg) {
    return { cat: 'F', label: '待付款', emoji: '💰', desc: 'PI/付款信息已发，等付款' };
  }

  // === 物流/发货 ===
  if (shipping && realOurMsg) {
    return { cat: 'G', label: '物流中', emoji: '🚚', desc: '讨论了发货/运费/物流' };
