// 读取P0/P1清单
const files = (await import('fs')).readdirSync(DATA_DIR).filter(f => f.includes('P0P1深抓清单'));
if (files.length === 0) {
  console.log('❌ 未找到P0P1深抓清单，先运行 extract-all-v2.mjs');
  return;
}
const listFile = files.sort().reverse()[0];
const p0p1List = JSON.parse(readFileSync(join(DATA_DIR, listFile), 'utf8'));

console.log(`[deep-scrape] 准备深抓 ${p0p1List.length} 个P0/P1客户`);
console.log(`  P0: ${p0p1List.filter(c => c.priority === 'P0').length}人`);
console.log(`  P1: ${p0p1List.filter(c => c.priority === 'P1').length}人\n`);

const { browser, talkFrame } = await connect();
console.log('✅ 已连接\n');

const results = [];
const skipped = [];
let successCount = 0;

try {
  // ⭐ Scroll sidebar to load ALL conversations into DOM (fixes 15%→90%+)
  console.log('滚动侧边栏加载全部会话...');
  await scrollSidebarToLoadAll(talkFrame);

  // 获取完整会话列表（现在DOM里有全部人了）
  const convList = await getConversationList(talkFrame);
  console.log(`当前DOM会话列表: ${convList.length}个\n`);

  // 创建名字→索引映射（使用模糊匹配）
  const nameToIndex = {};
  convList.forEach(c => { nameToIndex[c.name] = c.index; });

  // 辅助函数：用模糊匹配找到客户的DOM索引
  function findInConvList(targetName) {
    // 精确匹配
    if (nameToIndex[targetName] !== undefined) return nameToIndex[targetName];
    // 模糊匹配
    for (const c of convList) {
      if (fuzzyMatchName(c.name, targetName)) return c.index;
    }
    return undefined;
  }

  // 只处理P0客户（优先级最高）
  const p0Customers = p0p1List.filter(c => c.priority === 'P0');
  const p1Customers = p0p1List.filter(c => c.priority === 'P1');

  const toScrape = [...p0Customers, ...p1Customers];

  for (let i = 0; i < toScrape.length; i++) {
    const target = toScrape[i];
    const idx = findInConvList(target.name);

    if (idx === undefined) {
      skipped.push(target.name + '(DOM中未找到)');
      continue;
    }

    process.stdout.write(`[${i + 1}/${toScrape.length}] ${target.priority} ${target.name}...`);

