async function main() {
  console.log('[状态报告] 读取最新数据...');
  const data = loadLatest('2026-');
  console.log(`   ${data.stats.total} 客户, P0:${data.stats.P0} P1:${data.stats.P1} P2:${data.stats.P2} P3:${data.stats.P3}`);

  // 分类
  const groups = {};
  for (const c of data.customers) {
    const result = classify(c);
    if (!groups[result.cat]) groups[result.cat] = { ...result, items: [] };
    groups[result.cat].items.push(c);
  }

  // 排序
  const order = ['A', 'A2', 'I', 'C', 'D', 'S', 'F', 'G', 'H', 'J', 'P2', 'Z'];
  const sorted = order.filter(k => groups[k]).map(k => groups[k]);

  // 生成 Word
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');
  const sections = [];

  // 标题
  const children = [
    new Paragraph({
      children: [new TextRun({ text: '小满 OKKI 客户状态清单', bold: true, size: 44, color: '16213E', font: 'Microsoft YaHei' })],
      alignment: AlignmentType.CENTER, spacing: { after: 100 },
    }),
    new Paragraph({
      children: [new TextRun({ text: `数据采集：${dateStr}  ·  共 ${data.stats.total} 个客户  ·  仅列状态，不打方案`, size: 20, color: '636E72', font: 'Microsoft YaHei' })],
      alignment: AlignmentType.CENTER, spacing: { after: 400 },
    }),
    // 摘要
    new Paragraph({
      children: [new TextRun({ text: `📩 未读: ${groups.A?groups.A.items.length:0}  ·  ⚠️ 售后: ${groups.I?groups.I.items.length:0}  ·  📋 待报价: ${groups.C?groups.C.items.length:0}  ·  ⏳ 报价已发: ${groups.D?groups.D.items.length:0}  ·  💰 待付款: ${groups.F?groups.F.items.length:0}  ·  🚚 物流中: ${groups.G?groups.G.items.length:0}  ·  🔵 待回访: ${(groups.P2?groups.P2.items.length:0)+(groups.J?groups.J.items.length:0)}  ·  ⚪ 待激活: ${groups.Z?groups.Z.items.length:0}`, size: 18, color: '636E72', font: 'Microsoft YaHei' })],
      alignment: AlignmentType.CENTER, spacing: { after: 300 },
    }),
  ];

  // 每个分类
  for (const g of sorted) {
    if (g.items.length === 0) continue;

    children.push(
      new Paragraph({
        children: [new TextRun({ text: `${g.emoji} ${g.label}  (${g.items.length}人)`, bold: true, size: 24, color: '16213E', font: 'Microsoft YaHei' })],
        spacing: { before: 300, after: 60 },
        border: { bottom: { color: 'E94560', size: 2, space: 1 } },
      }),
      new Paragraph({
        children: [new TextRun({ text: g.desc, size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
        spacing: { after: 120 },
      })
    );

    // 表格
    const headerRow = new TableRow({
      children: ['客户名', '国家', '等级', '最后联系', '最新消息摘要'].map(text =>
        new TableCell({
          children: [new Paragraph({ children: [new TextRun({ text, bold: true, size: 16, color: 'FFFFFF', font: 'Microsoft YaHei' })], alignment: AlignmentType.CENTER })],
          shading: { type: ShadingType.SOLID, color: '16213E' },
          width: { size: text === '客户名' ? 22 : text === '最新消息摘要' ? 50 : 12, type: WidthType.PERCENTAGE },
        })
      ),
    });

    const rows = g.items.map(c => {
      const rawMsg = (c.latestMessageContent || '').replace(/\n/g, ' ').substring(0, 80);
      const displayMsg = isSystemMsg(c.latestMessageContent || '') ? '[系统提示]' : rawMsg;
      return new TableRow({
        children: [
          c.name || '?',
          c.countryCode || '?',
          c.buyerLevel || '?',
          daysAgo(c.lastContactTime),
          displayMsg || '(空)',
        ].map((text, i) =>
          new TableCell({
            children: [new Paragraph({ children: [new TextRun({ text, size: 16, font: 'Microsoft YaHei' })], alignment: i < 4 ? AlignmentType.CENTER : AlignmentType.LEFT })],
            width: { size: i === 0 ? 22 : i === 4 ? 50 : 12, type: WidthType.PERCENTAGE },
          })
        ),
      });
    });

    children.push(new Table({ rows: [headerRow, ...rows], width: { size: 100, type: WidthType.PERCENTAGE } }));
  }

  // 尾部
  children.push(
    new Paragraph({ spacing: { before: 400 }, children: [] }),
    new Paragraph({
      children: [new TextRun({ text: '说明：只列客户状态，不打执行方案。选中具体客户后可针对性地做五步分析和执行方案。', size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
      alignment: AlignmentType.CENTER,
    })
  );

  sections.push({ children });

  const doc = new Document({ sections });
  const buffer = await Packer.toBuffer(doc);
  const ts = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const outPath = join(DESKTOP, `客户状态清单_${ts}.docx`);
  writeFileSync(outPath, buffer);
  console.log(`\n✅ 已生成: ${outPath}`);
  console.log(`   包含 ${sorted.length} 个分类，共 ${data.stats.total} 个客户`);
}

main().catch(err => { console.error('错误:', err.message); process.exit(1); });

