/**
 * 客户状态清单 — 基于真实对话内容，不依赖平台元数据
 */
import { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, AlignmentType, WidthType, BorderStyle, ShadingType } from 'docx';
import { writeFileSync, readFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import os from 'os';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const DESKTOP = join(os.homedir(), 'Desktop');

const SYS = [/automatic reception/i,/由于您介入/i,/Marco大模型/i,/买家有流失/i,/AI给您生成/i,/建议查看/i,/一旦离开平台/i,/反馈/,/You have a visitor/i,/pre-screened/i,/系统自动发送/];

function loadLatest(prefix) {
  const files = readdirSync(DATA_DIR).filter(f => f.startsWith(prefix) && f.endsWith('.json')).sort().reverse();
  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf8'));
}

function getRealMsgs(messages) {
  return (messages || []).filter(m => m.text && m.text.length > 3 && !SYS.some(p => p.test(m.text || '')));
}

function summary(msgs, maxLen = 140) {
  const last = msgs.slice(-3);
  return last.map(m => (m.side === 'received' ? '←' : '→') + (m.text || '').substring(0, maxLen).replace(/\n/g, ' ')).join(' | ');
}

async function main() {
  const data = loadLatest('2026-');
  const ds = loadLatest('deep_scrape_v7_');
  const dsMap = {};
  for (const r of (ds.results || [])) dsMap[r.name] = r;

  const groups = {
