      alignment: AlignmentType.CENTER, spacing: { after: 300 },
    }),
  ];

  for (const [key, g] of Object.entries(groups)) {
    if (g.customers.length === 0) continue;
    children.push(
      new Paragraph({
        children: [new TextRun({ text: `${g.emoji} ${g.label}  (${g.customers.length}人)`, bold: true, size: 24, color: '16213E', font: 'Microsoft YaHei' })],
        spacing: { before: 300, after: 40 },
        border: { bottom: { color: 'E94560', size: 2, space: 1 } },
      }),
      new Paragraph({
        children: [new TextRun({ text: g.desc, size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
        spacing: { after: 120 },
      })
    );

