      children: ['客户', '国家', '判断说明', '最近对话'].map(text =>
        new TableCell({
          children: [new Paragraph({ children: [new TextRun({ text, bold: true, size: 16, color: 'FFFFFF', font: 'Microsoft YaHei' })], alignment: AlignmentType.CENTER })],
          shading: { type: ShadingType.SOLID, color: '16213E' },
          width: { size: text === '客户' ? 18 : text === '最近对话' ? 40 : text === '判断说明' ? 28 : 10, type: WidthType.PERCENTAGE },
        })
      ),
    });

    const rows = g.customers.map(c => new TableRow({
      children: [
        c.name, c.country, c.note, c.summary,
      ].map((text, i) =>
        new TableCell({
          children: [new Paragraph({ children: [new TextRun({ text, size: 15, font: 'Microsoft YaHei' })], alignment: i < 3 ? AlignmentType.LEFT : AlignmentType.LEFT })],
          width: { size: i === 0 ? 18 : i === 3 ? 40 : i === 2 ? 28 : 10, type: WidthType.PERCENTAGE },
        })
      ),
    }));

    children.push(new Table({ rows: [headerRow, ...rows], width: { size: 100, type: WidthType.PERCENTAGE } }));
  }

  children.push(
    new Paragraph({ spacing: { before: 400 }, children: [] }),
    new Paragraph({
      children: [new TextRun({ text: '判断方法：逐条阅读每个客户的完整对话后人工归类，不使用关键词或平台元数据。选中具体客户后可做五步分析和执行方案。', size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
      alignment: AlignmentType.CENTER,
    })
  );

  const doc = new Document({ sections: [{ children }] });
  const buffer = await Packer.toBuffer(doc);
  const ts = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const outPath = join(DESKTOP, `客户状态清单_${ts}.docx`);
  writeFileSync(outPath, buffer);

  // Console summary
  console.log(`\n✅ 已生成: ${outPath}`);
  for (const [key, g] of Object.entries(groups)) {
    if (g.customers.length > 0) {
      console.log(`\n${g.label} (${g.customers.length}人)`);
      g.customers.forEach(c => console.log(`  ${c.name.padEnd(24)} | ${c.country} | ${c.note}`));
    }
  }
}
main().catch(e => { console.error(e.message); process.exit(1); });

