function countryOf(name, data) {
  const c = data.customers.find(x => x.name === name);
  return c ? c.countryCode : '?';
}

async function main() {
  const data = loadLatest('2026-');
  const ds = loadLatest('deep_scrape_v7_');
  const dsMap = {};
  for (const r of (ds.results || [])) dsMap[r.name] = r;

  const groups = {
    payment: { label: '💰 待确认付款/订单', emoji: '💰', desc: '地址已确认，PI已发或即将发，推进到最后一步', customers: [] },
    active: { label: '🔥 谈判中·近期活跃', emoji: '🔥', desc: '双方有来有回，在讨论价格/样品/规格/选款', customers: [] },
    quoted: { label: '⏳ 报价已发·等客户回应', emoji: '⏳', desc: '报价或详情已发，客户暂未继续回应', customers: [] },
    initial: { label: '🆕 初询阶段·需有效推进', emoji: '🆕', desc: '客户发了产品卡/问了价，刚开聊或用模板回了', customers: [] },
    stalled: { label: '📋 模板回复后客户沉默', emoji: '📋', desc: '我们发了模板问题（3问等），客户没再回应', customers: [] },
    low: { label: '⚪ 低意向/非采购', emoji: '⚪', desc: '对话极少、系统消息为主、或非真实采购意向', customers: [] },
  };

  for (const [name, info] of Object.entries(MANUAL)) {
    const dsC = dsMap[name];
    const msgs = dsC ? getRealMsgs(dsC.messages || []) : [];
    groups[info.cat].customers.push({
      name, country: countryOf(name, data),
      note: info.note,
      summary: msgs.length > 0 ? summary(msgs) : '[无对话]',
      msgs,
    });
  }

  // ===== 生成 Word =====
  const now = new Date();
  const children = [
    new Paragraph({
      children: [new TextRun({ text: '小满 OKKI 客户状态清单', bold: true, size: 44, color: '16213E', font: 'Microsoft YaHei' })],
      alignment: AlignmentType.CENTER, spacing: { after: 100 },
    }),
    new Paragraph({
      children: [new TextRun({ text: `基于真实对话逐条判断  ·  ${now.toLocaleDateString('zh-CN')}  ·  P0+P1 共 ${Object.keys(MANUAL).length} 人`, size: 20, color: '636E72', font: 'Microsoft YaHei' })],
      alignment: AlignmentType.CENTER, spacing: { after: 300 },
    }),
  ];

  for (const [key, g] of Object.entries(groups)) {
    if (g.customers.length === 0) continue;
    children.push(
      new Paragraph({
        children: [new TextRun({ text: `${g.emoji} ${g.label}  (${g.customers.length}人)`, bold: true, size: 24, color: '16213E', font: 'Microsoft YaHei' })],
        spacing: { before: 300, after: 40 },
        border: { bottom: { color: 'E94560', size: 2, space: 1 } },
      }),
      new Paragraph({
        children: [new TextRun({ text: g.desc, size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
        spacing: { after: 120 },
      })
    );

    const headerRow = new TableRow({
      children: ['客户', '国家', '判断说明', '最近对话'].map(text =>
        new TableCell({
          children: [new Paragraph({ children: [new TextRun({ text, bold: true, size: 16, color: 'FFFFFF', font: 'Microsoft YaHei' })], alignment: AlignmentType.CENTER })],
          shading: { type: ShadingType.SOLID, color: '16213E' },
          width: { size: text === '客户' ? 18 : text === '最近对话' ? 40 : text === '判断说明' ? 28 : 10, type: WidthType.PERCENTAGE },
        })
      ),
    });

    const rows = g.customers.map(c => new TableRow({
      children: [
        c.name, c.country, c.note, c.summary,
      ].map((text, i) =>
        new TableCell({
          children: [new Paragraph({ children: [new TextRun({ text, size: 15, font: 'Microsoft YaHei' })], alignment: i < 3 ? AlignmentType.LEFT : AlignmentType.LEFT })],
          width: { size: i === 0 ? 18 : i === 3 ? 40 : i === 2 ? 28 : 10, type: WidthType.PERCENTAGE },
        })
      ),
    }));

    children.push(new Table({ rows: [headerRow, ...rows], width: { size: 100, type: WidthType.PERCENTAGE } }));
  }

  children.push(
    new Paragraph({ spacing: { before: 400 }, children: [] }),
    new Paragraph({
      children: [new TextRun({ text: '判断方法：逐条阅读每个客户的完整对话后人工归类，不使用关键词或平台元数据。选中具体客户后可做五步分析和执行方案。', size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
      alignment: AlignmentType.CENTER,
    })
  );

  const doc = new Document({ sections: [{ children }] });
  const buffer = await Packer.toBuffer(doc);
  const ts = now.toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const outPath = join(DESKTOP, `客户状态清单_${ts}.docx`);
  writeFileSync(outPath, buffer);

  // Console summary
  console.log(`\n✅ 已生成: ${outPath}`);
  for (const [key, g] of Object.entries(groups)) {
    if (g.customers.length > 0) {
      console.log(`\n${g.label} (${g.customers.length}人)`);
      g.customers.forEach(c => console.log(`  ${c.name.padEnd(24)} | ${c.country} | ${c.note}`));
    }
  }
}
main().catch(e => { console.error(e.message); process.exit(1); });

