/**
 * 零风险深抓 — 侧边栏DOM点击，不跳转URL
 * 用法: node deep-scrape-dom.mjs [人数]
 * 默认20个最新客户
 */
import { chromium } from 'playwright';
import { writeFileSync, readFileSync, readdirSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const CDP_URL = 'http://127.0.0.1:9222';
const LIMIT = parseInt(process.argv[2]) || 20;
const CLICK_DELAY = 2500;  // ms between clicks
const SYS = [/automatic reception/i,/由于您介入/i,/Marco大模型/i,/买家有流失/i,/AI给您生成/i,/建议查看/i,/一旦离开平台/i,/反馈/,/系统自动发送/];

async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) throw new Error('未找到小满页面');
  const talkFrame = page.frames()[1];
  if (!talkFrame) throw new Error('未找到聊天 iframe');
  return { browser, page, talkFrame };
}

// 滚动侧边栏直到加载全部会话
async function scrollSidebarFull(talkFrame) {
  console.log('[1/4] 滚动侧边栏加载全部会话...');
  const result = await talkFrame.evaluate(() => {
    const list = document.querySelector('.seller-conversation-list') ||
      document.querySelector('.conversation-list-content') ||
      document.querySelector('.im-conversation-list-container');
    if (!list) return { total: 0, error: 'no list container' };

    let lastCount = 0, stable = 0;
    const maxScrolls = 100;
    for (let i = 0; i < maxScrolls; i++) {
      list.scrollTop += 800;
      const items = document.querySelectorAll('.contact-item-container');
      if (items.length === lastCount) {
        stable++;
        if (stable >= 5) break;
      } else {
        stable = 0;
        lastCount = items.length;
      }
    }
    list.scrollTop = 0; // 回到顶部
    return { total: lastCount };
  });
  await new Promise(r => setTimeout(r, 500));
  console.log(`   侧边栏加载完成: ${result.total} 个会话`);
  return result.total;
}

// 获取侧边栏会话列表
async function getConvList(talkFrame) {
  return talkFrame.evaluate(() => {
    return Array.from(document.querySelectorAll('.contact-item-container')).map((el, idx) => {
      const right = el.querySelector('.contact-right');
      const nameText = right ? (right.textContent || '').trim() : '';
      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:/])/);
      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 35).trim();
      return { index: idx, name, el };
    });
  });
}

// 点击侧边栏会话，等待聊天面板更新
async function clickConv(talkFrame, index) {
  // 点击
  await talkFrame.evaluate((idx) => {
    const items = document.querySelectorAll('.contact-item-container');
    if (items[idx]) {
      items[idx].scrollIntoView({ block: 'center' });
      items[idx].click();
    }
  }, index);

  // 等待消息加载
  await new Promise(r => setTimeout(r, CLICK_DELAY));

  // 检查是否加载成功
  try {
    await talkFrame.waitForFunction(() => {
      const msgs = document.querySelectorAll('.message-item, .msg-item, [class*="message"]');
      return msgs.length > 0;
    }, { timeout: 3000 });
  } catch (e) {
    // 可能没有消息或加载慢，继续
  }
  await new Promise(r => setTimeout(r, 800));
}

// 提取当前聊天面板的消息
async function extractMessages(talkFrame) {
  return talkFrame.evaluate(() => {
    const msgs = [];
    const selectors = [
      '.message-item', '.msg-item', '.chat-message', '.im-message',
      '[class*="message-item"]', '[class*="msg-wrap"]', '.message-row',
