(async()=>{
  const browser=await chromium.connectOverCDP('http://127.0.0.1:9222');
  const tf=browser.contexts()[0].pages().find(p=>p.url().includes('xiaoman')).frames()[1];

  // Check store proxies  
  const info=await tf.evaluate(()=>{
    const results={};

    // Check __StoreProxyReady
    for(const key of ['__StoreProxyReady2','__StoreProxyReady3','__StoreProxyExec2','__StoreProxyExec3']){
      if(window[key]){
        try{
          if(typeof window[key]==='function'){
            results[key+'_type']='function';
            // Try calling ready to see what it returns
            try{
              const r=window[key]({namespace:'conversation'});
              results[key+'_result']=JSON.stringify(r).substring(0,200);
            }catch(e){
              results[key+'_callError']=e.message;
            }
          } else {
            results[key+'_type']=typeof window[key];
          }
        }catch(e){}
      }
    }

    // Check __sortConversation__
    if(window.__sortConversation__){
      results.sortConv='function';
    }

    // Try to find any object with message data by checking common patterns  
    // Look for the mtop library
    const allGlobals=Object.getOwnPropertyNames(window).filter(k=>{
      try{return typeof window[k]!=='function'&&typeof window[k]!=='undefined'&&!k.startsWith('webkit')&&!k.startsWith('on')}
      catch(e){return false}
    });

    // Search for anything containing 'message' in its name
    const msgGlobals=allGlobals.filter(k=>/message|chat|conversation|im/i.test(k));
